import{_ as e,o as i,c as o,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"新手引导","description":"","frontmatter":{"read_when":["设计 macOS 新手引导助手","实现认证或身份设置"],"summary":"OpenSoul 的首次运行新手引导流程（macOS 应用）","title":"新手引导","x-i18n":{"generated_at":"2026-02-03T07:54:07Z","model":"claude-opus-4-5","provider":"pi","source_hash":"ae883b2deb1f9032be7c47a04d67e1741dffbdcc4445de1e0bbaa976e606bc10","source_path":"start/onboarding.md","workflow":15}},"headers":[],"relativePath":"zh-CN/start/onboarding.md","filePath":"zh-CN/start/onboarding.md","lastUpdated":1771906665000}'),t={name:"zh-CN/start/onboarding.md"};function l(n,a,r,d,h,c){return i(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="新手引导-macos-应用" tabindex="-1"><a class="header-anchor" href="#新手引导-macos-应用">#</a> 新手引导（macOS 应用）</h1><p>本文档描述<strong>当前</strong>的首次运行新手引导流程。目标是流畅的&quot;第 0 天&quot;体验：选择 Gateway 网关运行位置、连接认证、运行向导，然后让智能体自行引导。</p><h2 id="页面顺序-当前" tabindex="-1"><a class="header-anchor" href="#页面顺序-当前">#</a> 页面顺序（当前）</h2><ol><li>欢迎 + 安全提示</li><li><strong>Gateway 网关选择</strong>（本地 / 远程 / 稍后配置）</li><li><strong>认证（Anthropic OAuth）</strong> — 仅限本地</li><li><strong>设置向导</strong>（Gateway 网关驱动）</li><li><strong>权限</strong>（TCC 提示）</li><li><strong>CLI</strong>（可选）</li><li><strong>新手引导聊天</strong>（专用会话）</li><li>就绪</li></ol><h2 id="_1-欢迎-安全提示" tabindex="-1"><a class="header-anchor" href="#_1-欢迎-安全提示">#</a> 1) 欢迎 + 安全提示</h2><p>阅读显示的安全提示并相应决定。</p><h2 id="_2-本地-vs-远程" tabindex="-1"><a class="header-anchor" href="#_2-本地-vs-远程">#</a> 2) 本地 vs 远程</h2><p><strong>Gateway 网关</strong>在哪里运行？</p><ul><li><strong>本地（此 Mac）：</strong> 新手引导可以在本地运行 OAuth 流程并写入凭证。</li><li><strong>远程（通过 SSH/Tailnet）：</strong> 新手引导<strong>不会</strong>在本地运行 OAuth；凭证必须存在于 Gateway 网关主机上。</li><li><strong>稍后配置：</strong> 跳过设置并保持应用未配置状态。</li></ul><p>Gateway 网关认证提示：</p><ul><li>向导现在即使对于 loopback 也会生成<strong>令牌</strong>，因此本地 WS 客户端必须认证。</li><li>如果你禁用认证，任何本地进程都可以连接；仅在完全受信任的机器上使用。</li><li>对于多机器访问或非 loopback 绑定，使用<strong>令牌</strong>。</li></ul><h2 id="_3-仅限本地的认证-anthropic-oauth" tabindex="-1"><a class="header-anchor" href="#_3-仅限本地的认证-anthropic-oauth">#</a> 3) 仅限本地的认证（Anthropic OAuth）</h2><p>macOS 应用支持 Anthropic OAuth（Claude Pro/Max）。流程：</p><ul><li>打开浏览器进行 OAuth（PKCE）</li><li>要求用户粘贴 <code>code#state</code> 值</li><li>将凭证写入 <code>~/.opensoul/credentials/oauth.json</code></li></ul><p>其他提供商（OpenAI、自定义 API）目前通过环境变量或配置文件配置。</p><h2 id="_4-设置向导-gateway-网关驱动" tabindex="-1"><a class="header-anchor" href="#_4-设置向导-gateway-网关驱动">#</a> 4) 设置向导（Gateway 网关驱动）</h2><p>应用可以运行与 CLI 相同的设置向导。这使新手引导与 Gateway 网关端行为保持同步，避免在 SwiftUI 中重复逻辑。</p><h2 id="_5-权限" tabindex="-1"><a class="header-anchor" href="#_5-权限">#</a> 5) 权限</h2><p>新手引导请求以下所需的 TCC 权限：</p><ul><li>通知</li><li>辅助功能</li><li>屏幕录制</li><li>麦克风 / 语音识别</li><li>自动化（AppleScript）</li></ul><h2 id="_6-cli-可选" tabindex="-1"><a class="header-anchor" href="#_6-cli-可选">#</a> 6) CLI（可选）</h2><p>应用可以通过 npm/pnpm 安装全局 <code>opensoul</code> CLI，以便终端工作流和 launchd 任务开箱即用。</p><h2 id="_7-新手引导聊天-专用会话" tabindex="-1"><a class="header-anchor" href="#_7-新手引导聊天-专用会话">#</a> 7) 新手引导聊天（专用会话）</h2><p>设置完成后，应用会打开一个专用的新手引导聊天会话，让智能体可以自我介绍并指导后续步骤。这使首次运行指导与你的正常对话分开。</p><h2 id="智能体引导仪式" tabindex="-1"><a class="header-anchor" href="#智能体引导仪式">#</a> 智能体引导仪式</h2><p>在首次智能体运行时，OpenSoul 会引导一个工作区（默认 <code>~/.opensoul/workspace</code>）：</p><ul><li>初始化 <code>AGENTS.md</code>、<code>BOOTSTRAP.md</code>、<code>IDENTITY.md</code>、<code>USER.md</code></li><li>运行简短的问答仪式（一次一个问题）</li><li>将身份 + 偏好写入 <code>IDENTITY.md</code>、<code>USER.md</code>、<code>SOUL.md</code></li><li>完成后删除 <code>BOOTSTRAP.md</code>，使其只运行一次</li></ul><h2 id="可选-gmail-钩子-手动" tabindex="-1"><a class="header-anchor" href="#可选-gmail-钩子-手动">#</a> 可选：Gmail 钩子（手动）</h2><p>Gmail Pub/Sub 设置目前是手动步骤。使用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> webhooks</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gmail</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> you@gmail.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>参阅 <a href="/docs/automation/gmail-pubsub">/automation/gmail-pubsub</a> 了解详情。</p><h2 id="远程模式说明" tabindex="-1"><a class="header-anchor" href="#远程模式说明">#</a> 远程模式说明</h2><p>当 Gateway 网关在另一台机器上运行时，凭证和工作区文件存储在<strong>该主机上</strong>。如果你需要在远程模式下使用 OAuth，请在 Gateway 网关主机上创建：</p><ul><li><code>~/.opensoul/credentials/oauth.json</code></li><li><code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li></ul>',34)])])}const g=e(t,[["render",l]]);export{u as __pageData,g as default};
